public int getMaxLen(int[] nums) {
    int maxLength = 0, currentLen = 0, currentNegLen = 0;

    for (int num : nums) {
        if (num > 0) {
            ++currentLen;
            if (currentNegLen > 0) ++currentNegLen;
        } else if (num < 0) {
            int tmp = currentLen;
            currentLen = currentNegLen;
            currentNegLen = tmp + 1;
        } else {
            currentLen = 0;
            currentNegLen = 0;
        }
        maxLength = Math.max(maxLength, currentLen);
    }

    return maxLength;
}
```

